function solve(s) {
    const segments = [];
    const seen = new Set();
    let currentSegment = '';

    for (let i = 0; i < s.length; i++) {
        currentSegment += s[i];
        if (!seen.has(currentSegment)) {
            seen.add(currentSegment);
            segments.push(currentSegment);
            currentSegment = '';
        }
    }

    return segments;
}
